from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
from collections import Counter, defaultdict


def _load_passage_manager(index_path: str) -> PassageManager:
    """
    Helper that validates the index path and returns a PassageManager.

    Raises FileNotFoundError if the index (or its underlying metadata) is
    missing in a way that prevents PassageManager from loading.
    """
    path = Path(index_path)

    # Basic existence check for the index directory/file
    if not path.exists():
        raise FileNotFoundError(f"Index path not found: {index_path}")

    try:
        pm = PassageManager(index_path=str(path))
    except FileNotFoundError as e:
        # Propagate as required by the spec
        raise FileNotFoundError(
            f"Index metadata file not found for path: {index_path}"
        ) from e
    except Exception as e:
        # If PassageManager signals missing metadata via another exception type,
        # normalize to FileNotFoundError to match the contract.
        if "metadata" in str(e).lower() and "not found" in str(e).lower():
            raise FileNotFoundError(
                f"Index metadata file not found for path: {index_path}"
            ) from e
        raise

    return pm


def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

    Args:
        index_path: Path to the LEANN index file

    Returns:
        Dictionary containing:
        {
            "total_passages": total number of passages,
            "metadata_fields": list of unique metadata field names,
            "field_value_counts": dictionary of field value counts
        }

    Raises:
        FileNotFoundError: If index metadata file is not found
    """
    pm = _load_passage_manager(index_path)

    total_passages = 0
    field_names = set()
    field_value_counts: Dict[str, Counter] = defaultdict(Counter)

    # Assuming PassageManager is iterable or exposes a way to iterate passages
    for passage in pm:
        total_passages += 1
        metadata = getattr(passage, "metadata", None) or {}
        for key, value in metadata.items():
            field_names.add(key)
            # Normalize value to string for consistent counting
            field_value_counts[key][str(value)] += 1

    # Convert Counters to regular dicts for JSON-serializable return
    field_value_counts_serializable: Dict[str, Dict[str, int]] = {
        field: dict(counter) for field, counter in field_value_counts.items()
    }

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(field_names),
        "field_value_counts": field_value_counts_serializable,
    }


def analyze_index_coverage(
    index_path: str, required_fields: List[str]
) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

    Args:
        index_path: Path to the LEANN index file
        required_fields: List of metadata field names that should be present

    Returns:
        Dictionary containing:
        {
            "coverage_percentage": percentage of passages that have all required fields,
            "field_coverage": dictionary mapping field name to coverage percentage,
            "missing_fields": list of required fields not found in any passage
        }

    Raises:
        FileNotFoundError: If index metadata file is not found
    """
    pm = _load_passage_manager(index_path)

    total_passages = 0
    passages_with_all_required = 0
    field_presence_counts = {field: 0 for field in required_fields}
    fields_seen_in_any_passage = set()

    for passage in pm:
        total_passages += 1
        metadata = getattr(passage, "metadata", None) or {}

        # Track fields seen at all
        fields_seen_in_any_passage.update(metadata.keys())

        # Per-field coverage
        for field in required_fields:
            if field in metadata and metadata[field] is not None:
                field_presence_counts[field] += 1

        # All-required coverage
        if all(
            field in metadata and metadata[field] is not None
            for field in required_fields
        ):
            passages_with_all_required += 1

    if total_passages == 0:
        # Avoid division by zero; define coverage as 0 when there are no passages
        coverage_percentage = 0.0
        field_coverage = {field: 0.0 for field in required_fields}
    else:
        coverage_percentage = (passages_with_all_required / total_passages) * 100.0
        field_coverage = {
            field: (count / total_passages) * 100.0
            for field, count in field_presence_counts.items()
        }

    missing_fields = [
        field for field in required_fields if field not in fields_seen_in_any_passage
    ]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields,
    }

